class Solution {
public:
    int findMin(vector<int>& nums) {
        int low = 0;
        int high = nums.size() - 1;
        while (low < high) {
            int pivot = low + (high - low) / 2;
            if (nums[pivot] < nums[high]) {
                high = pivot; // pivot 可能就是最小值，不能减一
            }
            else {
                low = pivot + 1; // nums[pivot] >= nums[high]，最小值一定在 pivot 右侧
            }
        }
        return nums[low];
    }
};
